/* wif-das-classificationtotemapping-interface-sql-oracle.xml - insertClassificationToteMappingWave - 분류토트매핑 웨이브 INSERT SQL */
INSERT INTO TWIF_DAS_CLASSIFTOTE_MAPP_WA
(
	WASEQ
	,CTKEY
	,OWKEY
	,WAHDKEY
	,IFCD
	,WIFIFID
	,IFID
	,IFREQDT
	,IFTYPE
	,IFSRCMODULE
	,IFTGTMODULE
	,IFSTATUS
	,IFERRCD
	,IFERRMSG
	,IFPRCSDATE
	,ORD
	,INSERTDATE
	,INSERTURKEY
	,UPDATEDATE
	,UPDATEURKEY
	,IFRETRYYN
	,IFRETRYIFID
)
VALUES
(
	#{waSeq}
	,#{ctKey}
	,#{owKey}
	,#{waHdKey}
	,#{ifCd}
	,#{wifIfId}
	,#{ifId}
	,#{ifReqDt}
	,#{ifType}
	,#{ifSrcModule}
	,#{ifTgtModule}
	,#{ifStatus}
	,#{ifErrCd}
	,#{ifErrMsg}
	,#{ifPrcsDate}
	,#{ord}
	,#{sysdate}
	,#{surkey}
	,#{sysdate}
	,#{surkey}
	,#{ifretryyn}
	,#{ifretryifid}
)

